// components/DarkModeToggle.tsx
"use client";

import { Moon, Sun } from "lucide-react";
import { useTheme } from "./providers/ThemeProvider";

export function ThemeModeToggle() {
    const { isDark, toggleTheme } = useTheme();

    return (
        <button
            onClick={toggleTheme}
            role="switch"
            aria-checked={isDark}
            aria-label="Toggle dark mode"
            className="relative inline-flex items-center w-14 h-8 sm:w-20 sm:h-10 rounded-full px-1 sm:px-2 bg-secondary border border-border transition-all duration-200 hover:border-primary/50 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:ring-offset-2 focus-visible:ring-offset-background"
        >
            <span className="sr-only">Toggle dark mode</span>

            {/* Track - subtle background */}
            <span
                className={`absolute inset-0 rounded-full transition-colors duration-200 ${isDark ? 'bg-primary/80' : 'bg-secondary'}`}
            />

            {/* Knob */}
            <span
                className={`relative z-10 block h-6 w-6 sm:h-8 sm:w-8 rounded-full bg-background shadow-md transform transition-transform duration-300 ${isDark ? 'translate-x-6 sm:translate-x-8' : 'translate-x-0 sm:translate-x-1'}`}
            />

            {/* Icons */}
            <Sun
                size={12}
                className={`absolute left-2 sm:left-3 z-20 transition-opacity duration-200 ${isDark ? 'opacity-40' : 'opacity-100 text-primary-foreground'}`}
            />
            <Moon
                size={12}
                className={`absolute right-2 sm:right-3 z-20 transition-opacity duration-200 ${isDark ? 'opacity-100 text-primary-foreground' : 'opacity-40'}`}
            />
        </button>
    );
}

